  template <typename RNG> inline void
  write_array(RNG& base_rng, Eigen::Matrix<double,-1,1>& params_r,
              Eigen::Matrix<double,-1,1>& vars, const bool
              emit_transformed_parameters = true, const bool
              emit_generated_quantities = true, std::ostream*
              pstream = nullptr) const {
    const size_t num_params__ = K_h + 1 + 1 + K_clusters + 1 + K_Z + 1 +
      N_pays + 1 + K_Z + 1 + N_pays + 1 + K_Z + 1 + N_pays + 1 + K_Z + 1 +
      N_pays + K_v + 1 + 1 + D_v + 1 + K_clusters + D_v + 1;
    const size_t num_transformed = emit_transformed_parameters * (K_clusters
      + N_pays + N_pays + N_pays + N_pays + 1 + N_pays + N_pays + N_pays +
      N_pays + D_v + D_v + N_h + N_h + N_v + N_v);
    const size_t num_gen_quantities = emit_generated_quantities *
      (log_lik_h_1dim__ + log_lik_v_1dim__ + is_mig_hat_1dim__ + N_test +
      N_test + N_test + 1);
    const size_t num_to_write = num_params__ + num_transformed +
      num_gen_quantities;
    std::vector<int> params_i;
    vars = Eigen::Matrix<double,-1,1>::Constant(num_to_write,
             std::numeric_limits<double>::quiet_NaN());
    write_array_impl(base_rng, params_r, params_i, vars,
      emit_transformed_parameters, emit_generated_quantities, pstream);
  }
